// ============================================================================
// CONVERGIO WEB - TYPE DEFINITIONS
// Migrated from ConvergioApp native macOS application
// ============================================================================

// === MAESTRO TYPES ===

export type MaestroVoice =
  | 'alloy'
  | 'ash'
  | 'ballad'
  | 'coral'
  | 'echo'
  | 'sage'
  | 'shimmer'
  | 'verse';

export type Subject =
  | 'mathematics'
  | 'physics'
  | 'chemistry'
  | 'biology'
  | 'history'
  | 'geography'
  | 'italian'
  | 'english'
  | 'art'
  | 'music'
  | 'civics'
  | 'economics'
  | 'computerScience'
  | 'health'
  | 'philosophy'
  | 'internationalLaw';

export interface Maestro {
  id: string;
  name: string;
  subject: Subject;
  specialty: string;
  voice: MaestroVoice;
  voiceInstructions: string;  // How to speak/personality for voice
  teachingStyle: string;
  avatar: string;
  color: string;
  systemPrompt: string;
  greeting: string;
}

// === VOICE SESSION TYPES ===

export type VoiceSessionState =
  | 'idle'
  | 'connecting'
  | 'connected'
  | 'listening'
  | 'processing'
  | 'speaking'
  | 'error';

export type VoiceConnectionState = 'idle' | 'connecting' | 'connected' | 'error';

/**
 * Handle returned by useVoiceSession hook.
 * Used to pass voice session state between components without re-creating connections.
 */
export interface VoiceSessionHandle {
  isConnected: boolean;
  isListening: boolean;
  isSpeaking: boolean;
  isMuted: boolean;
  connectionState: VoiceConnectionState;
  connect: (maestro: Maestro, connectionInfo: { provider: 'azure'; proxyPort?: number }) => Promise<void>;
  disconnect: () => void;
  toggleMute: () => void;
}

export type EmotionType =
  | 'neutral'
  | 'joy'
  | 'excitement'
  | 'curiosity'
  | 'confusion'
  | 'frustration'
  | 'anxiety'
  | 'boredom'
  | 'distraction';

export interface Emotion {
  type: EmotionType;
  confidence: number;
  color: string;
}

export interface TranscriptEntry {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: Date;
  emotion?: Emotion;
}

export interface AudioLevels {
  input: number;
  output: number;
}

// === EDUCATION TYPES ===

export type QuestionType = 'multiple_choice' | 'true_false' | 'open_ended';

export interface Question {
  id: string;
  text: string;
  type: QuestionType;
  options?: string[];
  correctAnswer: string | number;
  hints: string[];
  explanation: string;
  difficulty: 1 | 2 | 3 | 4 | 5;
  subject: Subject;
  topic: string;
}

export interface Quiz {
  id: string;
  title: string;
  subject: Subject;
  questions: Question[];
  timeLimit?: number; // seconds
  masteryThreshold: number; // 0-100
  xpReward: number;
}

export interface QuizResult {
  quizId: string;
  score: number;
  totalQuestions: number;
  correctAnswers: number;
  timeSpent: number;
  masteryAchieved: boolean;
  xpEarned: number;
  completedAt: Date;
}

// === FLASHCARD TYPES (FSRS-5) ===

export type CardState = 'new' | 'learning' | 'review' | 'relearning';
export type Rating = 'again' | 'hard' | 'good' | 'easy';

// ============================================================================
// CONVERGIO WEB - DATABASE SCHEMA
// SQLite for local, PostgreSQL for cloud (same schema works for both)
// ============================================================================

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "sqlite"
}

// ============================================================================
// USER & PROFILE
// ============================================================================

model User {
  id        String   @id @default(cuid())
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  profile       Profile?
  settings      Settings?
  progress      Progress?
  sessions          StudySession[]
  flashcards        FlashcardProgress[]
  quizResults       QuizResult[]
  conversations     Conversation[]
  learnings         Learning[]
  pushSubscriptions PushSubscription[]

  // Issue #64: Consolidated localStorage data
  accessibility     AccessibilitySettings?
  onboarding        OnboardingState?
  pomodoroStats     PomodoroStats?
  calendarEvents    CalendarEvent[]
  htmlSnippets      HtmlSnippet[]
  homeworkSessions  HomeworkSession[]
}

model Profile {
  id            String   @id @default(cuid())
  userId        String   @unique
  user          User     @relation(fields: [userId], references: [id], onDelete: Cascade)

  name          String?
  age           Int?
  schoolYear    Int?
  schoolLevel   String   @default("superiore")
  gradeLevel    String?
  learningGoals String   @default("[]")

  // Character preferences (coach and buddy selection)
  preferredCoach String?  // melissa, roberto, chiara, andrea, favij
  preferredBuddy String?  // mario, noemi, enea, bruno, sofia

  createdAt     DateTime @default(now())
  updatedAt     DateTime @updatedAt
}

// ============================================================================
// SETTINGS
// ============================================================================

model Settings {
  id            String  @id @default(cuid())
  userId        String  @unique
  user          User    @relation(fields: [userId], references: [id], onDelete: Cascade)

  // Appearance
  theme         String  @default("system")
  language      String  @default("it")
  accentColor   String  @default("blue")

  // Accessibility
  fontSize           String  @default("medium")
  highContrast       Boolean @default(false)
  dyslexiaFont       Boolean @default(false)
  reducedMotion      Boolean @default(false)
  voiceEnabled       Boolean @default(true)
  simplifiedLanguage Boolean @default(false)
  adhdMode           Boolean @default(false)

  // AI Provider
  provider      String  @default("azure")
  model         String  @default("gpt-4o")
  budgetLimit   Float   @default(50.0)
  totalSpent    Float   @default(0.0)

  // Parent Mode Consent (Issue #63)
  parentChatConsentAt DateTime?  // When parent consented to chat with professors

  // Parent Dashboard (Issue #64)
  parentDashboardLastViewed DateTime?  // When parent last viewed the dashboard

  // Azure Cost Configuration
  azureCostConfig String?  // JSON: {token_cost, audio_cost, etc.}

  createdAt     DateTime @default(now())
  updatedAt     DateTime @updatedAt
}

// ============================================================================
// PROGRESS & GAMIFICATION
// ============================================================================

model Progress {
  id                String    @id @default(cuid())
  userId            String    @unique
  user              User      @relation(fields: [userId], references: [id], onDelete: Cascade)

  xp                Int       @default(0)
  level             Int       @default(1)

  // Streak
  streakCurrent     Int       @default(0)
  streakLongest     Int       @default(0)
  lastStudyDate     DateTime?

  // Aggregates
  totalStudyMinutes Int       @default(0)
  questionsAsked    Int       @default(0)
  sessionsThisWeek  Int       @default(0)

  // Complex data as JSON
  achievements      String    @default("[]")
  masteries         String    @default("[]")

  createdAt         DateTime  @default(now())
  updatedAt         DateTime  @updatedAt
}

model StudySession {
  id          String    @id @default(cuid())
  userId      String
  user        User      @relation(fields: [userId], references: [id], onDelete: Cascade)

  maestroId   String
  subject     String
  startedAt   DateTime  @default(now())
  endedAt     DateTime?
  duration    Int?
  xpEarned    Int       @default(0)
  questions   Int       @default(0)

  // Student self-evaluation (1-5 stars)
  studentRating    Int?
  studentFeedback  String?

  // AI Maestro evaluation (1-10 score)
  maestroScore     Int?
  maestroFeedback  String?
  strengths        String?   // JSON array
  areasToImprove   String?   // JSON array

  // Session context
  topics           String    @default("[]") // JSON array of topics covered
  conversationId   String?   // Link to Conversation

  // Tools created during session
  materials        Material[]

  @@index([userId])
  @@index([startedAt])
  @@index([conversationId])
}

// ============================================================================
// EDUCATION: FLASHCARDS & QUIZZES
// ============================================================================

model FlashcardProgress {
  id             String    @id @default(cuid())
  userId         String
  user           User      @relation(fields: [userId], references: [id], onDelete: Cascade)

  cardId         String
  deckId         String?

  // FSRS Algorithm State
  difficulty     Float     @default(0.0)
  stability      Float     @default(0.0)
  retrievability Float     @default(1.0)
  state          String    @default("new")

  // Review tracking
  reps           Int       @default(0)
  lapses         Int       @default(0)
  lastReview     DateTime?
  nextReview     DateTime?

  createdAt      DateTime  @default(now())
  updatedAt      DateTime  @updatedAt

  @@unique([userId, cardId])
  @@index([userId])
  @@index([nextReview])
}
